'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useUserProfile } from './useUserProfile';
import { toast } from '@/hooks/use-toast';
import {
    FinancialCategory,
    FinancialCategoryInsert,
    FinancialCategoryUpdate,
    FinancialCategoryWithStats,
    CategoryType,
} from '@/types/financial';

interface UseFinancialCategoriesOptions {
    type?: CategoryType;
}

export function useFinancialCategories(options: UseFinancialCategoriesOptions = {}) {
    const { type } = options;
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user, profile } = useUserProfile();

    // Query for categories
    const {
        data: categories = [],
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: ['financial-categories', type],
        queryFn: async (): Promise<FinancialCategoryWithStats[]> => {
            let query = supabase
                .from('financial_categories')
                .select('*')
                .order('name');

            if (type) {
                query = query.eq('type', type);
            }

            const { data, error } = await query;

            if (error) {
                console.error('Error fetching categories:', error);
                throw error;
            }

            return (data || []) as FinancialCategoryWithStats[];
        },
        staleTime: 0,
        refetchOnMount: true,
        refetchOnWindowFocus: true,
    });

    // Create category mutation
    const createCategory = useMutation({
        mutationFn: async (newCategory: Omit<FinancialCategoryInsert, 'organization_id' | 'user_id'>) => {
            if (!user?.id) throw new Error('User not authenticated');

            const categoryData: FinancialCategoryInsert = {
                ...newCategory,
                user_id: user.id,
                organization_id: profile?.organization_id || null,
            };

            const { data, error } = await supabase
                .from('financial_categories')
                .insert(categoryData as never)
                .select()
                .single();

            if (error) throw error;
            return data as FinancialCategory;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-categories'] });
            toast({
                title: 'Categoria criada',
                description: 'A categoria foi criada com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error creating category:', error);
            toast({
                title: 'Erro ao criar categoria',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Update category mutation
    const updateCategory = useMutation({
        mutationFn: async ({
            id,
            updates,
        }: {
            id: string;
            updates: FinancialCategoryUpdate;
        }) => {
            const { data, error } = await supabase
                .from('financial_categories')
                .update(updates as never)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;
            return data as FinancialCategory;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-categories'] });
            toast({
                title: 'Categoria atualizada',
                description: 'A categoria foi atualizada com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error updating category:', error);
            toast({
                title: 'Erro ao atualizar categoria',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Delete category mutation
    const deleteCategory = useMutation({
        mutationFn: async (id: string) => {
            // Check if category has transactions
            const { count } = await supabase
                .from('financial_transactions')
                .select('*', { count: 'exact', head: true })
                .eq('category_id', id);

            if (count && count > 0) {
                throw new Error(
                    'Não é possível excluir uma categoria com transações associadas.'
                );
            }

            const { error } = await supabase
                .from('financial_categories')
                .delete()
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-categories'] });
            toast({
                title: 'Categoria removida',
                description: 'A categoria foi removida com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error deleting category:', error);
            toast({
                title: 'Erro ao remover categoria',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Filter categories by type
    const entradaCategories = categories.filter((c) => c.type === 'entrada');
    const saidaCategories = categories.filter((c) => c.type === 'saida');

    return {
        categories,
        entradaCategories,
        saidaCategories,
        isLoading,
        error,
        refetch,
        createCategory,
        updateCategory,
        deleteCategory,
    };
}
