'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useUserProfile } from './useUserProfile';
import { toast } from '@/hooks/use-toast';
import {
    FinancialTransaction,
    FinancialTransactionWithDetails,
    FinancialTransactionInsert,
    FinancialTransactionUpdate,
    TransactionFilters,
} from '@/types/financial';

interface UseFinancialTransactionsOptions {
    filters?: TransactionFilters;
    limit?: number;
}

export function useFinancialTransactions(options: UseFinancialTransactionsOptions = {}) {
    const { filters, limit = 100 } = options;
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user, profile, isSecretaria } = useUserProfile();

    // Query for transactions with relations
    const {
        data: transactions = [],
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: ['financial-transactions', user?.id, filters, limit, isSecretaria],
        queryFn: async (): Promise<FinancialTransactionWithDetails[]> => {
            if (!user?.id) return [];

            // First, get the account IDs we have access to
            let accountIds: string[] = [];

            if (isSecretaria) {
                // Secretary: get accounts from linked doctors
                const { data: links } = await supabase
                    .from('secretary_doctor_links')
                    .select('doctor_id')
                    .eq('secretary_id', user.id) as { data: { doctor_id: string }[] | null };

                if (links && links.length > 0) {
                    const doctorIds = links.map((l) => l.doctor_id);
                    const { data: accounts } = await supabase
                        .from('financial_accounts')
                        .select('id')
                        .in('user_id', doctorIds) as { data: { id: string }[] | null };

                    accountIds = accounts?.map((a) => a.id) || [];
                }
            } else {
                // Regular user: get own accounts
                const { data: accounts } = await supabase
                    .from('financial_accounts')
                    .select('id')
                    .eq('user_id', user.id) as { data: { id: string }[] | null };

                accountIds = accounts?.map((a) => a.id) || [];
            }

            if (accountIds.length === 0) return [];

            // Build query with relations
            let query = supabase
                .from('financial_transactions')
                .select(`
                    *,
                    account:financial_accounts(id, name, type, bank_name, is_default),
                    category:financial_categories(id, name, type, color, icon),
                    contact:crm_contacts(id, full_name, company),
                    deal:crm_deals(id, title, value),
                    costs:transaction_costs(*)
                `)
                .in('account_id', accountIds)
                .order('transaction_date', { ascending: false })
                .limit(limit);

            // Apply filters
            if (filters?.startDate) {
                query = query.gte('transaction_date', filters.startDate);
            }
            if (filters?.endDate) {
                query = query.lte('transaction_date', filters.endDate);
            }
            if (filters?.type) {
                query = query.eq('type', filters.type);
            }
            if (filters?.category_id) {
                query = query.eq('category_id', filters.category_id);
            }
            if (filters?.account_id) {
                query = query.eq('account_id', filters.account_id);
            }
            if (filters?.status) {
                query = query.eq('status', filters.status);
            }
            if (filters?.search) {
                query = query.ilike('description', `%${filters.search}%`);
            }

            const { data, error } = await query;

            if (error) {
                console.error('Error fetching transactions:', error);
                throw error;
            }

            return (data || []) as unknown as FinancialTransactionWithDetails[];
        },
        enabled: !!user?.id,
    });

    // Create transaction mutation
    const createTransaction = useMutation({
        mutationFn: async (
            newTransaction: Omit<FinancialTransactionInsert, 'user_id' | 'organization_id'>
        ) => {
            if (!user?.id) throw new Error('User not authenticated');

            const transactionData: FinancialTransactionInsert = {
                ...newTransaction,
                user_id: user.id,
                organization_id: profile?.organization_id || null,
            };

            const { data, error } = await supabase
                .from('financial_transactions')
                .insert(transactionData as never)
                .select()
                .single();

            if (error) throw error;

            // Update account balance
            if (newTransaction.account_id) {
                await updateAccountBalance(newTransaction.account_id);
            }

            return data as FinancialTransaction;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-transactions'] });
            queryClient.invalidateQueries({ queryKey: ['financial-accounts'] });
            queryClient.invalidateQueries({ queryKey: ['financial-metrics'] });
            toast({
                title: 'Transação criada',
                description: 'A transação foi registrada com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error creating transaction:', error);
            toast({
                title: 'Erro ao criar transação',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Update transaction mutation
    const updateTransaction = useMutation({
        mutationFn: async ({
            id,
            updates,
        }: {
            id: string;
            updates: FinancialTransactionUpdate;
        }) => {
            // Get original transaction to check account change
            const { data: original } = await supabase
                .from('financial_transactions')
                .select('account_id')
                .eq('id', id)
                .single() as { data: { account_id: string } | null };

            const { data, error } = await supabase
                .from('financial_transactions')
                .update(updates as never)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;

            const transaction = data as FinancialTransaction;

            // Update balances for affected accounts
            if (updates.account_id && original?.account_id !== updates.account_id) {
                if (original?.account_id) {
                    await updateAccountBalance(original.account_id);
                }
                await updateAccountBalance(updates.account_id);
            } else if (transaction.account_id) {
                await updateAccountBalance(transaction.account_id);
            }

            return transaction;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-transactions'] });
            queryClient.invalidateQueries({ queryKey: ['financial-accounts'] });
            queryClient.invalidateQueries({ queryKey: ['financial-metrics'] });
            toast({
                title: 'Transação atualizada',
                description: 'A transação foi atualizada com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error updating transaction:', error);
            toast({
                title: 'Erro ao atualizar transação',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Delete transaction mutation
    const deleteTransaction = useMutation({
        mutationFn: async (id: string) => {
            // Get transaction to update account balance
            const { data: transaction } = await supabase
                .from('financial_transactions')
                .select('account_id')
                .eq('id', id)
                .single() as { data: { account_id: string } | null };

            const { error } = await supabase
                .from('financial_transactions')
                .delete()
                .eq('id', id);

            if (error) throw error;

            // Update account balance
            if (transaction?.account_id) {
                await updateAccountBalance(transaction.account_id);
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-transactions'] });
            queryClient.invalidateQueries({ queryKey: ['financial-accounts'] });
            queryClient.invalidateQueries({ queryKey: ['financial-metrics'] });
            toast({
                title: 'Transação removida',
                description: 'A transação foi removida com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error deleting transaction:', error);
            toast({
                title: 'Erro ao remover transação',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Helper function to update account balance
    async function updateAccountBalance(accountId: string) {
        if (!accountId) return;

        const { data: txns } = await supabase
            .from('financial_transactions')
            .select('amount, type')
            .eq('account_id', accountId)
            .eq('status', 'completed') as { data: { amount: number | null; type: string }[] | null };

        const calculatedBalance = (txns || []).reduce((sum, t) => {
            return t.type === 'entrada' ? sum + (t.amount || 0) : sum - (t.amount || 0);
        }, 0);

        const { data: account } = await supabase
            .from('financial_accounts')
            .select('initial_balance')
            .eq('id', accountId)
            .single() as { data: { initial_balance: number } | null };

        const totalBalance = (account?.initial_balance || 0) + calculatedBalance;

        await supabase
            .from('financial_accounts')
            .update({ balance: totalBalance } as never)
            .eq('id', accountId);
    }

    return {
        transactions,
        isLoading,
        error,
        refetch,
        createTransaction,
        updateTransaction,
        deleteTransaction,
    };
}
