'use client';

import { useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { TransactionsTable } from "./TransactionsTable";
import { useFinancialTransactions } from "@/hooks/useFinancialTransactions";
import { Button } from "@/components/ui/button";
import { Plus } from "lucide-react";
import { TransactionForm } from "./TransactionForm";

export default function SinalTab() {
    const { transactions } = useFinancialTransactions();
    const [isCreateOpen, setIsCreateOpen] = useState(false);

    return (
        <Card>
            <CardHeader className="flex flex-row items-center justify-between">
                <div>
                    <CardTitle>Controle de Sinais (Receitas)</CardTitle>
                    <CardDescription>Gerenciamento de adiantamentos e sinais de cirurgias.</CardDescription>
                </div>
                <Button onClick={() => setIsCreateOpen(true)}>
                    <Plus className="mr-2 h-4 w-4" /> Novo Sinal
                </Button>
            </CardHeader>
            <CardContent>
                <TransactionsTable
                    initialData={transactions}
                    defaultFilterType="entrada"
                    lockFilterType={true}
                />
            </CardContent>

            <TransactionForm
                open={isCreateOpen}
                onOpenChange={setIsCreateOpen}
                defaultType="entrada"
                onSuccess={() => setIsCreateOpen(false)}
            />
        </Card>
    );
}
